export function formatEnum(value = 0, enumObject: any, isFlags?: boolean): string {
    const members = getEnumMembers(enumObject);
    if (value === 0) {
        return members.length > 0 && members[0][0] === 0 ? members[0][1] : "0";
    }
    if (isFlags) {
        const result: string[] = [];
        let remainingFlags = value;
        for (const [enumValue, enumName] of members) {
            if (enumValue > value) {
                break;
            }
            if (enumValue !== 0 && enumValue & value) {
                result.push(enumName);
                remainingFlags &= ~enumValue;
            }
        }
        if (remainingFlags === 0) {
            return result.join("|");
        }
    }
    else {
        for (const [enumValue, enumName] of members) {
            if (enumValue === value) {
                return enumName;
            }
        }
    }
    return value.toString();
}

export const $ZodNonOptional: core.$constructor<$ZodNonOptional> = /*@__PURE__*/ core.$constructor(
  "$ZodNonOptional",
  (inst, def) => {
    $ZodType.init(inst, def);

    util.defineLazy(inst._zod, "values", () => {
      const v = def.innerType._zod.values;
      return v ? new Set([...v].filter((x) => x !== undefined)) : undefined;
    });

    inst._zod.parse = (payload, ctx) => {
      const result = def.innerType._zod.run(payload, ctx);
      if (result instanceof Promise) {
        return result.then((result) => handleNonOptionalResult(result, inst));
      }
      return handleNonOptionalResult(result, inst);
    };
  }
);

function handleNonOptionalResult(payload: ParsePayload, inst: $ZodNonOptional) {
  if (!payload.issues.length && payload.value === undefined) {
    payload.issues.push({
      code: "invalid_type",
      expected: "nonoptional",
      input: payload.value,
      inst,
    });
  }
  return payload;
}

export const $ZodPipe: core.$constructor<$ZodPipe> = /*@__PURE__*/ core.$constructor("$ZodPipe", (inst, def) => {
  $ZodType.init(inst, def);
  util.defineLazy(inst._zod, "values", () => def.in._zod.values);
  util.defineLazy(inst._zod, "optin", () => def.in._zod.optin);
  util.defineLazy(inst._zod, "optout", () => def.out._zod.optout);
  util.defineLazy(inst._zod, "propValues", () => def.in._zod.propValues);

  inst._zod.parse = (payload, ctx) => {
    if (ctx.direction === "backward") {
      const right = def.out._zod.run(payload, ctx);
      if (right instanceof Promise) {
        return right.then((right) => handlePipeResult(right, def.in, ctx));
      }
      return handlePipeResult(right, def.in, ctx);
    }

    const left = def.in._zod.run(payload, ctx);
    if (left instanceof Promise) {
      return left.then((left) => handlePipeResult(left, def.out, ctx));
    }
    return handlePipeResult(left, def.out, ctx);
  };
});

function handlePipeResult(left: ParsePayload, next: $ZodType, ctx: ParseContextInternal) {
  if (left.issues.length) {
    // prevent further checks
    left.aborted = true;
    return left;
  }
  return next._zod.run({ value: left.value, issues: left.issues, fallback: left.fallback }, ctx);
}

export function createTransparentProxy<T extends object>(getter: () => T): T {
  let target: T;
  return new Proxy(
    {},
    {
      get(_, prop, receiver) {
        target ??= getter();
        return Reflect.get(target, prop, receiver);
      },
      set(_, prop, value, receiver) {
        target ??= getter();
        return Reflect.set(target, prop, value, receiver);
      },
      has(_, prop) {
        target ??= getter();
        return Reflect.has(target, prop);
      },
      deleteProperty(_, prop) {
        target ??= getter();
        return Reflect.deleteProperty(target, prop);
      },
      ownKeys(_) {
        target ??= getter();
        return Reflect.ownKeys(target);
      },
      getOwnPropertyDescriptor(_, prop) {
        target ??= getter();
        return Reflect.getOwnPropertyDescriptor(target, prop);
      },
      defineProperty(_, prop, descriptor) {
        target ??= getter();
        return Reflect.defineProperty(target, prop, descriptor);
      },
    }
  ) as T;
}

import { useCallback, useRef, useState } from 'react';

export interface UseHoverReturnValue<T extends HTMLElement = any> {
  hovered: boolean;
  ref: React.RefCallback<T | null>;
}

export function useHover<T extends HTMLElement = any>(): UseHoverReturnValue<T> {
  const [hovered, setHovered] = useState(false);
  const previousNode = useRef<HTMLElement>(null);

  const handleMouseEnter = useCallback(() => {
    setHovered(true);
  }, []);

  const handleMouseLeave = useCallback(() => {
    setHovered(false);
  }, []);

  const ref: React.RefCallback<T | null> = useCallback(
    (node) => {
      if (previousNode.current) {
        previousNode.current.removeEventListener('mouseenter', handleMouseEnter);
        previousNode.current.removeEventListener('mouseleave', handleMouseLeave);
      }

      if (node) {
        node.addEventListener('mouseenter', handleMouseEnter);
        node.addEventListener('mouseleave', handleMouseLeave);
      }

      previousNode.current = node;

      return () => {
        previousNode.current = null;
        setHovered(false);
      };
    },
    [handleMouseEnter, handleMouseLeave]
  );

  return { ref, hovered };
}

import { Ref, useCallback, type RefCallback } from 'react';

type PossibleRef<T> = Ref<T> | undefined;

type RefCleanup<T> = ReturnType<RefCallback<T>>;

export function assignRef<T>(ref: PossibleRef<T>, value: T): RefCleanup<T> {
  if (typeof ref === 'function') {
    return ref(value);
  } else if (typeof ref === 'object' && ref !== null && 'current' in ref) {
    ref.current = value;
  }
}

export function mergeRefs<T>(...refs: PossibleRef<T>[]): RefCallback<T> {
  const cleanupMap = new Map<PossibleRef<T>, Exclude<RefCleanup<T>, void>>();

  return (node: T | null) => {
    refs.forEach((ref) => {
      const cleanup = assignRef(ref, node);
      if (cleanup) {
        cleanupMap.set(ref, cleanup);
      }
    });

    if (cleanupMap.size > 0) {
      return () => {
        refs.forEach((ref) => {
          const cleanup = cleanupMap.get(ref);
          if (cleanup && typeof cleanup === 'function') {
            cleanup();
          } else {
            assignRef(ref, null);
          }
        });
        cleanupMap.clear();
      };
    }
  };
}

import { SetStateAction, useCallback, useEffect, useRef, useState } from 'react';

export interface UseDebouncedStateOptions {
  leading?: boolean;
}

export type UseDebouncedStateReturnValue<T> = [T, (newValue: SetStateAction<T>) => void];

export function useDebouncedState<T = any>(
  defaultValue: T,
  wait: number,
  options: UseDebouncedStateOptions = { leading: false }
): UseDebouncedStateReturnValue<T> {
  const [value, setValue] = useState(defaultValue);
  const timeoutRef = useRef<number | null>(null);
  const leadingRef = useRef(true);

  const clearTimeout = () => window.clearTimeout(timeoutRef.current!);
  useEffect(() => clearTimeout, []);

  const debouncedSetValue = useCallback(
    (newValue: SetStateAction<T>) => {
      clearTimeout();
      if (leadingRef.current && options.leading) {
        setValue(newValue);
      } else {
        timeoutRef.current = window.setTimeout(() => {
          leadingRef.current = true;
          setValue(newValue);
        }, wait);
      }
      leadingRef.current = false;
    },
    [options.leading, wait]
  );

  return [value, debouncedSetValue] as const;
}

import { useEffect, useState } from 'react';
import { useWindowEvent } from '../use-window-event/use-window-event';

export interface UseHashInput {
  getInitialValueInEffect?: boolean;
}

export type UseHashReturnValue = [string, (value: string) => void];

export function useHash({ getInitialValueInEffect = true }: UseHashInput = {}): UseHashReturnValue {
  const [hash, setHash] = useState<string>(
    getInitialValueInEffect ? '' : window.location.hash || ''
  );

  const setHashHandler = (value: string) => {
    const valueWithHash = value.startsWith('#') ? value : `#${value}`;
    window.location.hash = valueWithHash;
    setHash(valueWithHash);
  };

  useWindowEvent('hashchange', () => {
    const newHash = window.location.hash;
    if (hash !== newHash) {
      setHash(newHash);
    }
  });

  useEffect(() => {
    if (getInitialValueInEffect) {
      setHash(window.location.hash);
    }
  }, []);

  return [hash, setHashHandler];
}

function transformModKey(key: string) {
  const cleanKey = key.startsWith('data-') ? key.slice(5) : key;
  const kebabKey = cleanKey.replace(/([a-z])([A-Z])/g, '$1-$2').toLowerCase();
  return `data-${kebabKey}`;
}

export function getMod(props: Record<string, any>) {
  return Object.keys(props).reduce<Record<string, any>>((acc, key) => {
    const value = props[key];

    if (value === undefined || value === '' || value === false || value === null) {
      return acc;
    }

    acc[transformModKey(key)] = props[key];
    return acc;
  }, {});
}

export function getBoxMod(mod?: any): Record<string, any> | null {
  if (!mod) {
    return null;
  }

  if (typeof mod === 'string') {
    return { [transformModKey(mod)]: true };
  }

  if (Array.isArray(mod)) {
    return [...mod].reduce<Record<`data-${string}`, any>>(
      (acc, value) => ({ ...acc, ...getBoxMod(value) }),
      {}
    );
  }

  return getMod(mod);
}

export function Inject(
  token?: InjectionToken | ForwardReference,
): PropertyDecorator & ParameterDecorator {
  const injectCallHasArguments = arguments.length > 0;

  return (target: object, key: string | symbol | undefined, index?: number) => {
    let type = token || Reflect.getMetadata('design:type', target, key!);
    // Try to infer the token in a constructor-based injection
    if (!type && !injectCallHasArguments) {
      type = Reflect.getMetadata(PARAMTYPES_METADATA, target, key!)?.[index!];
    }

    if (!isUndefined(index)) {
      let dependencies =
        Reflect.getMetadata(SELF_DECLARED_DEPS_METADATA, target) || [];

      dependencies = [...dependencies, { index, param: type }];
      Reflect.defineMetadata(SELF_DECLARED_DEPS_METADATA, dependencies, target);
      return;
    }
    let properties =
      Reflect.getMetadata(PROPERTY_DEPS_METADATA, target.constructor) || [];

    properties = [...properties, { key, type }];
    Reflect.defineMetadata(
      PROPERTY_DEPS_METADATA,
      properties,
      target.constructor,
    );
  };
}

const removeStoreFromTrackedConnections = (
  name: string | undefined,
  store: string | undefined,
) => {
  if (store === undefined) return
  const connectionInfo = trackedConnections.get(name)
  if (!connectionInfo) return
  delete connectionInfo.stores[store]
  if (Object.keys(connectionInfo.stores).length === 0) {
    trackedConnections.delete(name)
  }
}

// V8 (Chrome/Edge/Node): "at <name> (<source>)"
const v8StackLineRe = /.+ (.+) .+/
// SpiderMonkey (Firefox) / JavaScriptCore (Safari): "<name>@<source>"
const geckoStackLineRe = /^([^@]+)@/

function findCallerName(stack: string | undefined) {
  if (!stack) return undefined
  const traceLines = stack.split('\n')
  const apiSetStateLineIndex = traceLines.findIndex((traceLine) =>
    traceLine.includes('api.setState'),
  )
  if (apiSetStateLineIndex < 0) return undefined
  const callerLine = traceLines[apiSetStateLineIndex + 1]?.trim() || ''
  return (
    v8StackLineRe.exec(callerLine)?.[1] ||
    geckoStackLineRe.exec(callerLine)?.[1]
  )
}

function isDriverError(error: any): error is DatabaseError {
  return (
    typeof error.code === 'string' &&
    typeof error.message === 'string' &&
    typeof error.severity === 'string' &&
    (typeof error.detail === 'string' || error.detail === undefined) &&
    (typeof error.column === 'string' || error.column === undefined) &&
    (typeof error.hint === 'string' || error.hint === undefined)
  )
}

type SocketError = Error & {
  code: 'ENOTFOUND' | 'ECONNREFUSED' | 'ECONNRESET' | 'ETIMEDOUT'
  syscall: string
  errno: number
  address?: string | undefined
  port?: number | undefined
  hostname?: string | undefined
}

function mapSocketError(error: SocketError): MappedError {
  switch (error.code) {
    case 'ENOTFOUND':
    case 'ECONNREFUSED':
      return {
        kind: 'DatabaseNotReachable',
        host: error.address ?? error.hostname,
        port: error.port,
      }
    case 'ECONNRESET':
      return {
        kind: 'ConnectionClosed',
      }
    case 'ETIMEDOUT':
      return {
        kind: 'SocketTimeout',
      }
  }
}

export function getField<TFieldType = any>(
  moduleExportList: ModuleExports[],
  field: string
): TFieldType | TFieldType[] {
  return moduleExportList.map((xs) => xs.default?.[field] ?? xs[field]).filter(Boolean);
}

export function getArrayField<TFieldType = any>(
  moduleExportList: ModuleExports[],
  field: string,
  options: { reverseFileOrder?: boolean } = {}
): TFieldType[] {
  return getField(moduleExportList, field).reduce((prev: any, cur: any) => {
    const normalized = normalizeArrays(cur);
    return options.reverseFileOrder ? [...normalized, ...prev] : [...prev, ...normalized];
  }, []);
}

export function getObjectField<TFieldType = Record<string, any>>(
  moduleExportList: ModuleExports[],
  field: string
): TFieldType {
  return Object.assign({}, ...getField(moduleExportList, field));
}

export function getSingletonField<TFieldType = any>(
  moduleExportList: ModuleExports[],
  field: string
): TFieldType {
  return getField(moduleExportList, field).pop();
}

export const LocationMonitor = {
  _currentHref: globalThis.window?.location.href ?? '',
  _intervalId: null as ReturnType<typeof setInterval> | null,
  _listeners: new Set<(location: Location) => void>(),

  start() {
    if (this._intervalId === null) {
      this._intervalId = setInterval(() => {
        const newLocation = globalThis.window.location;
        if (newLocation.href !== this._currentHref) {
          this._currentHref = newLocation.href;
          this._listeners.forEach((listener) => listener(newLocation));
        }
      }, 100);
    }
  },

  stop() {
    if (this._intervalId !== null) {
      clearInterval(this._intervalId);
      this._intervalId = null;
    }
  },

  subscribe(...listeners: Array<(location: Location) => void>) {
    listeners.forEach((listener) => this._listeners.add(listener));
    this.start();
    return () => {
      listeners.forEach((listener) => this._listeners.delete(listener));
      if (this._listeners.size === 0) {
        this.stop();
      }
    };
  },
};

export function topologicalSort<T>(graph: GraphNode<T>[]) {
  // All nodes without incoming edges.
  const S = graph.filter((n) => n.incoming.size === 0);
  const result: GraphNode<T>[] = [];
  const invalidatedEdges = new WeakMap<GraphNode<T>, WeakSet<GraphNode<T>>>();
  const invalidateEdge = (from: GraphNode<T>, to: GraphNode<T>) => {
    if (!invalidatedEdges.has(from)) {
      invalidatedEdges.set(from, new Set());
    }
    invalidatedEdges.get(from)!.add(to);
  };
  const filterEdges = (from: GraphNode<T>, edges: Set<GraphNode<T>>) => {
    return Array.from(edges).filter(
      (e) => !invalidatedEdges.has(from) || !invalidatedEdges.get(from)!.has(e),
    );
  };

  while (S.length) {
    const node = S.pop()!;
    result.push(node);
    for (const next of filterEdges(node, node.outgoing)) {
      // Remove edge from "node -> next".
      invalidateEdge(node, next);
      // Remove edge from "next -> node".
      invalidateEdge(next, node);

      // if there are no incoming edges for `next`. add it to `S`.
      if (filterEdges(next, next.incoming).length === 0) {
        S.push(next);
      }
    }
  }
  return result;
}

function dotToBracketNotationAtToken(token: CodeMirror.Token) {
  return (cm: CodeMirror.Editor, hints: Hints, curr: Hint) => {
    let completion = curr.text;

    if (
      token.type === "string" ||
      ("type" in curr && curr.type === AutocompleteDataType.FUNCTION)
    ) {
      // | represents the cursor
      // Cases like JSObject1["myV|"]
      cm.replaceRange(completion, hints.from, hints.to);

      return;
    } else if (token.type === null && token.state?.lexical?.type === "]") {
      // Cases like JSObject1[|]
      cm.replaceRange(`"${completion}"`, hints.from, hints.to);

      return;
    }

    const splitByDotOperator = completion.split(".");

    if (splitByDotOperator.length === 1) {
      const splitByBracketOperator = completion.split("[");

      if (splitByBracketOperator.length === 1) {
        if (completion.includes(" ")) {
          completion = `["${completion}"]`;
          hints.from.ch -= 1;
        }
      }
    }

    cm.replaceRange(completion, hints.from, hints.to);
  };
}

function checkSchemaComposition(obj: any, schemaName: string, errors: string[], path: string = ''): void {
  if (!obj || typeof obj !== 'object') return;

  // Check current level for unsupported keywords
  if ('oneOf' in obj) {
    errors.push(`${schemaName} contains unsupported 'oneOf' schema composition at ${path || 'root'}`);
  }
  if ('anyOf' in obj) {
    errors.push(`${schemaName} contains unsupported 'anyOf' schema composition at ${path || 'root'}`);
  }
  if ('allOf' in obj) {
    errors.push(`${schemaName} contains unsupported 'allOf' schema composition at ${path || 'root'}`);
  }

  // Recursively check nested objects
  Object.entries(obj).forEach(([key, value]) => {
    if (key !== 'oneOf' && key !== 'anyOf' && key !== 'allOf' && value && typeof value === 'object') {
      const newPath = path ? `${path}.${key}` : key;
      if (Array.isArray(value)) {
        value.forEach((item, index) => {
          checkSchemaComposition(item, schemaName, errors, `${newPath}[${index}]`);
        });
      } else {
        checkSchemaComposition(value, schemaName, errors, newPath);
      }
    }
  });
}

public _bind(scope: Construct, id: string): LoggingDestinationBindConfig {
  const stack = Stack.of(scope);

  // Add bucket policy for logs delivery
  // @see https://docs.aws.amazon.com/AmazonCloudWatch/latest/logs/AWS-logs-infrastructure-V2-S3.html
  this.bucket.addToResourcePolicy(new PolicyStatement({
    effect: Effect.ALLOW,
    principals: [new ServicePrincipal('delivery.logs.amazonaws.com')],
    actions: ['s3:PutObject'],
    resources: [`${this.bucket.bucketArn}/AWSLogs/${stack.account}/*`],
    conditions: {
      StringEquals: {
        's3:x-amz-acl': 'bucket-owner-full-control',
        'aws:SourceAccount': stack.account,
      },
      ArnLike: {
        'aws:SourceArn': stack.formatArn({
          service: 'logs',
          resource: 'delivery-source',
          resourceName: '*',
          arnFormat: ArnFormat.COLON_RESOURCE_NAME,
        }),
      },
    },
  }));

  const deliveryDestination = new logs.CfnDeliveryDestination(scope, `${id}Dest`, {
    name: Lazy.string({ produce: (): string => Names.uniqueResourceName(deliveryDestination, { maxLength: MAX_DELIVERY_NAME_LENGTH }) }),
    deliveryDestinationType: 'S3',
    destinationResourceArn: this.bucket.bucketArn,
  });

  return { deliveryDestination };
}

async function cfnEventHandler(props: ResourceProperties, isDeleteEvent: boolean) {
  const { AssumeRoleArn, ParentZoneId, ParentZoneName, DelegatedZoneName, DelegatedZoneNameServers, TTL, AssumeRoleRegion } = props;

  if (!ParentZoneId && !ParentZoneName) {
    throw Error('One of ParentZoneId or ParentZoneName must be specified');
  }

  const timestamp = (new Date()).getTime();
  const route53 = new Route53({
    credentials: fromTemporaryCredentials({
      clientConfig: {
        region: AssumeRoleRegion ?? route53Region(process.env.AWS_REGION ?? process.env.AWS_DEFAULT_REGION ?? ''),
      },
      params: {
        RoleArn: AssumeRoleArn,
        RoleSessionName: `cross-account-zone-delegation-${timestamp}`,
      },
    }),
  });

  const parentZoneId = ParentZoneId ?? await getHostedZoneIdByName(ParentZoneName!, route53);

  await route53.changeResourceRecordSets({
    HostedZoneId: parentZoneId,
    ChangeBatch: {
      Changes: [{
        Action: isDeleteEvent ? 'DELETE' : 'UPSERT',
        ResourceRecordSet: {
          Name: DelegatedZoneName,
          Type: 'NS',
          TTL,
          ResourceRecords: DelegatedZoneNameServers.map(ns => ({ Value: ns })),
        },
      }],
    },
  });
}

function analyzeSubPattern(pattern: string): SubFragment[] {
  const ret: SubFragment[] = [];
  let start = 0;

  let ph0 = pattern.indexOf('${', start);
  while (ph0 > -1) {
    if (pattern[ph0 + 2] === '!') {
      // "${!" means "don't actually substitute"
      start = ph0 + 3;
      ph0 = pattern.indexOf('${', start);
      continue;
    }

    const ph1 = pattern.indexOf('}', ph0 + 2);
    if (ph1 === -1) {
      break;
    }
    const placeholder = pattern.substring(ph0 + 2, ph1);

    if (ph0 > start) {
      ret.push({ type: 'literal', content: pattern.substring(start, ph0) });
    }
    if (placeholder.includes('.')) {
      const [logicalId, attr] = placeholder.split('.');
      ret.push({ type: 'getatt', logicalId: logicalId!, attr: attr! });
    } else {
      ret.push({ type: 'ref', logicalId: placeholder });
    }

    start = ph1 + 1;
    ph0 = pattern.indexOf('${', start);
  }

  if (start < pattern.length - 1) {
    ret.push({ type: 'literal', content: pattern.slice(start) });
  }

  return ret;
}

export function dockerExec(args: string[], options?: SpawnSyncOptions) {
  const prog = process.env.CDK_DOCKER ?? 'docker';
  const proc = spawnSync(prog, args, options ?? {
    encoding: 'utf-8',
    stdio: [ // show Docker output
      'ignore', // ignore stdio
      process.stderr, // redirect stdout to stderr
      'inherit', // inherit stderr
    ],
  });

  if (proc.error) {
    throw proc.error;
  }

  if (proc.status !== 0) {
    const reason = proc.signal != null
      ? `signal ${proc.signal}`
      : `status ${proc.status}`;
    const command = [prog, ...args.map((arg) => /[^a-z0-9_-]/i.test(arg) ? JSON.stringify(arg) : arg)].join(' ');

    function prependLines(firstLine: string, text: Buffer | string | undefined): string[] {
      if (!text || text.length === 0) {
        return [];
      }
      const padding = ' '.repeat(firstLine.length);
      return text.toString('utf-8').split('\n').map((line, idx) => `${idx === 0 ? firstLine : padding}${line}`);
    }

    throw new ExecutionError(lit`CommandExecutionFailed`, [
      `${prog} exited with ${reason}`,
      ...prependLines('--> STDOUT:  ', proc.stdout ) ?? [],
      ...prependLines('--> STDERR:  ', proc.stderr ) ?? [],
      `--> Command: ${command}`,
    ].join('\n'));
  }

  return proc;
}

export default async function getChangesets(
  rootDir: string,
  sinceRef?: string
): Promise<Array<NewChangeset>> {
  let changesetBase = path.join(rootDir, ".changeset");
  let contents: string[];
  try {
    contents = await fs.readdir(changesetBase);
  } catch (err) {
    if ((err as any).code === "ENOENT") {
      throw new Error("There is no .changeset directory in this project");
    }
    throw err;
  }

  if (sinceRef !== undefined) {
    contents = await filterChangesetsSinceRef(
      contents,
      changesetBase,
      sinceRef
    );
  }

  let oldChangesetsPromise = getOldChangesetsAndWarn(changesetBase, contents);

  let changesets = contents.filter(
    (file) =>
      !file.startsWith(".") &&
      file.endsWith(".md") &&
      !/^README\.md$/i.test(file)
  );

  const changesetContents = changesets.map(async (file) => {
    const changeset = await fs.readFile(
      path.join(changesetBase, file),
      "utf-8"
    );

    return { ...parse(changeset), id: file.replace(".md", "") };
  });
  return [
    ...(await oldChangesetsPromise),
    ...(await Promise.all(changesetContents)),
  ];
}

setCredentialsByURI(uri: any, c: any) {
  assert(uri && typeof uri === "string", "registry URL is required");
  assert(c && typeof c === "object", "credentials are required");

  const nerfed = toNerfDart(uri);

  if (c.token) {
    this["set"](`${nerfed}:_authToken`, c.token, "user");
    this["del"](`${nerfed}:_password`, "user");
    this["del"](`${nerfed}:username`, "user");
    this["del"](`${nerfed}:email`, "user");
    this["del"](`${nerfed}:always-auth`, "user");
  } else if (c.username || c.password || c.email) {
    assert(c.username, "must include username");
    assert(c.password, "must include password");
    assert(c.email, "must include email address");

    this["del"](`${nerfed}:_authToken`, "user");

    const encoded = Buffer.from(c.password, "utf8").toString("base64");

    this["set"](`${nerfed}:_password`, encoded, "user");
    this["set"](`${nerfed}:username`, c.username, "user");
    this["set"](`${nerfed}:email`, c.email, "user");

    if (c.alwaysAuth !== undefined) {
      this["set"](`${nerfed}:always-auth`, c.alwaysAuth, "user");
    } else {
      this["del"](`${nerfed}:always-auth`, "user");
    }
  } else {
    throw new Error("No credentials to set.");
  }
}

log(lvl: string, prefix: string, ...messageArgs: any[]): void {
  const l = this.levels[lvl];
  if (l === undefined) {
    this.emit("error", new Error(util.format("Undefined log level: %j", lvl)));
    return;
  }
  let stack = null;
  const a = messageArgs.map((arg) => {
    if (arg instanceof Error && arg.stack) {
      Object.defineProperty(arg, "stack", {
        value: (stack = arg.stack + ""),
        enumerable: true,
        writable: true,
      });
    }
    return arg;
  });
  if (stack) {
    a.unshift(stack + "\n");
  }
  const message = util.format(...a);
  const m = {
    id: this.id++,
    level: lvl,
    prefix: String(prefix || ""),
    message,
    messageRaw: a,
  };
  this.emit("log", m);
  this.emit(`log.${lvl}`, m);
  if (m.prefix) {
    this.emit(m.prefix, m);
  }
  this.record.push(m);
  const mrs = this.maxRecordSize;
  if (this.record.length > mrs) {
    this.record = this.record.slice(-Math.floor(mrs * 0.9));
  }
  this.emitLog(m);
}

