function decycle(object: any, replacer?: Function | null) {
  const objects = new WeakMap()

  function deepCopy(value, path) {
    let oldPath
    let newObj

    if (replacer != null) {
      value = replacer(value)
    }

    if (isObject(value)) {
      oldPath = objects.get(value)
      if (oldPath !== undefined) {
        return { $ref: oldPath }
      }

      objects.set(value, path)

      if (Array.isArray(value)) {
        newObj = []
        value.forEach((el, idx) => {
          newObj[idx] = deepCopy(el, path + "[" + idx + "]")
        })
      } else {
        newObj = {}
        Object.keys(value).forEach((name) => {
          newObj[name] = deepCopy(
            value[name],
            path + "[" + JSON.stringify(name) + "]"
          )
        })
      }
      return newObj
    }

    return !isPrimitive(value) ? value + "" : value
  }

  return deepCopy(object, "$")
}

private getPostgresCastType(path, field) {
  const graphqlToPostgresTypeMap = {
    Int: "::int",
    Float: "::double precision",
    Boolean: "::boolean",
    Date: "::timestamp",
    DateTime: "::timestamp",
    Time: "::time",
    "": "",
  }

  const defaultValues = {
    Int: "0",
    Float: "0",
    Boolean: "false",
    Date: "1970-01-01 00:00:00",
    DateTime: "1970-01-01 00:00:00",
    Time: "00:00:00",
    "": "",
  }

  const fullPath = [path, ...field]
  const prop = fullPath.pop()
  const fieldPath = fullPath.join(".")
  let graphqlType = this.getGraphQLType(fieldPath, prop)
  const isList = graphqlType.endsWith("[]")
  graphqlType = graphqlType.replace("[]", "")

  const cast =
    (graphqlToPostgresTypeMap[graphqlType] ?? "") + (isList ? "[]" : "")

  function generateCoalesceExpression(field) {
    const defaultValue = defaultValues[graphqlType]
    return `COALESCE(${field}, '${defaultValue}')${cast}`
  }

  return {
    cast,
    coalesce: generateCoalesceExpression,
  }
}

private _getFilenameForApiItem(apiItem: ApiItem): string {
  if (apiItem.kind === ApiItemKind.Model) {
    return 'index.md';
  }

  let baseName: string = '';
  for (const hierarchyItem of apiItem.getHierarchy()) {
    // For overloaded methods, add a suffix such as "MyClass.myMethod_2".
    let qualifiedName: string = Utilities.getSafeFilenameForName(hierarchyItem.displayName);
    if (ApiParameterListMixin.isBaseClassOf(hierarchyItem)) {
      if (hierarchyItem.overloadIndex > 1) {
        // Subtract one for compatibility with earlier releases of API Documenter.
        // (This will get revamped when we fix GitHub issue #1308)
        qualifiedName += `_${hierarchyItem.overloadIndex - 1}`;
      }
    }

    switch (hierarchyItem.kind) {
      case ApiItemKind.Model:
      case ApiItemKind.EntryPoint:
      case ApiItemKind.EnumMember:
        break;
      case ApiItemKind.Package:
        baseName = Utilities.getSafeFilenameForName(PackageName.getUnscopedName(hierarchyItem.displayName));
        break;
      default:
        baseName += '.' + qualifiedName;
    }
  }
  return baseName + '.md';
}

private _getTimestamp(useSeconds: boolean = false): string | undefined {
  // Create a date string with the current time

  // dateString === "2016-10-19T22:47:49.606Z"
  const dateString: string = new Date().toJSON();

  // Parse out 2 capture groups, the date and the time
  const dateParseRegex: RegExp = /([0-9]{4}-[0-9]{2}-[0-9]{2}).*([0-9]{2}:[0-9]{2}:[0-9]{2})/;

  // matches[1] === "2016-10-19"
  // matches[2] === "22:47:49"
  const matches: RegExpMatchArray | null = dateString.match(dateParseRegex);

  if (matches) {
    // formattedDate === "2016-10-19"
    const formattedDate: string = matches[1];

    let formattedTime: string;
    if (useSeconds) {
      // formattedTime === "22-47-49"
      formattedTime = matches[2].replace(':', '-');
    } else {
      // formattedTime === "22-47"
      const timeParts: string[] = matches[2].split(':');
      formattedTime = `${timeParts[0]}-${timeParts[1]}`;
    }

    return `${formattedDate}-${formattedTime}`;
  }
  return undefined;
}

