export function improvedNaiveSankeyLinkPathHorizontal(
  link: SankeyLayoutLink<true>,
  curveCorrection?: number,
) {
  const sx = link.source.x1!;
  const tx = link.target.x0!;
  // Weirdly this seems to work for any chart or node width change
  // But needs to be changed when the sankey height changes.
  const correction = curveCorrection ?? 5;
  const y0 = link.y0!;
  const y1 = link.y1!;
  const w = link.width!;
  const halfW = w / 2;
  const sy0 = y0 - halfW;
  const sy1 = y0 + halfW;
  const ty0 = y1 - halfW;
  const ty1 = y1 + halfW;

  const halfX = (tx - sx) / 2;

  const p = path();
  p.moveTo(sx, sy0);

  const isDecreasing = y0 > y1;
  const direction = isDecreasing ? -1 : 1;

  let cpx1 = sx + halfX + correction * direction;
  let cpy1 = sy0;
  let cpx2 = sx + halfX + correction * direction;
  let cpy2 = ty0;
  p.bezierCurveTo(cpx1, cpy1, cpx2, cpy2, tx, ty0);
  p.lineTo(tx, ty1);

  cpx1 = sx + halfX - correction * direction;
  cpy1 = ty1;
  cpx2 = sx + halfX - correction * direction;
  cpy2 = sy1;
  p.bezierCurveTo(cpx1, cpy1, cpx2, cpy2, sx, sy1);
  p.lineTo(sx, sy0);
  return p.toString();
}

function determineUserAgent(): string {
  let osIdentifier = 'unknown';
  let osVersion = 'unknown';
  if (process.platform === 'win32') {
    const version = os.release().split('.');
    osIdentifier = 'windows';
    osVersion = `${version[0]}.${version[1]}`;
  } else if (process.platform === 'darwin') {
    const version = execSync('sw_vers -productVersion', { stdio: ['ignore', 'pipe', 'ignore'] }).toString().trim().split('.');
    osIdentifier = 'macOS';
    osVersion = `${version[0]}.${version[1]}`;
  } else if (process.platform === 'linux') {
    const distroInfo = getLinuxDistributionInfoSync();
    if (distroInfo) {
      osIdentifier = distroInfo.id || 'linux';
      osVersion = distroInfo.version || 'unknown';
    } else {
      // Linux distribution without /etc/os-release.
      // Default to linux/unknown.
      osIdentifier = 'linux';
    }
  }
  const additionalTokens = [];
  if (process.env.CI)
    additionalTokens.push('CI/1');
  const serializedTokens = additionalTokens.length ? ' ' + additionalTokens.join(' ') : '';

  const { embedderName, embedderVersion } = getEmbedderName();
  return `Playwright/${getPlaywrightVersion()} (${os.arch()}; ${osIdentifier} ${osVersion}) ${embedderName}/${embedderVersion}${serializedTokens}`;
}

export function getAlignmentMarginInfo(
  arr: AlignmentColumnData[],
  res: FlexLayerAlignment[][] = [[], [], []],
  resIndex = 0,
): boolean[] {
  if (!arr.length) return [];

  const wrapInfo: FlexLayerAlignment[][] = getLayerWrappingInfo(
    arr,
    res,
    resIndex,
  );
  const marginInfo: {
    [key: string]: (arr: AlignmentColumnData[]) => boolean[];
  } = {
    // eslint-disable-next-line @typescript-eslint/no-unused-vars
    "300": (arr): boolean[] => [false, false, false],
    "120": (arr): boolean[] => [
      arr[0].columns > 0 && arr[1].columns + arr[2].columns > 0,
      false,
      false,
    ],
    "210": (arr): boolean[] => [
      arr[0].columns > 0 && arr[2].columns > 0,
      arr[1].columns > 0 && arr[2].columns > 0,
      false,
    ],
    "111": (arr): boolean[] => [
      arr[0].columns > 0,
      arr[1].columns > 0 && arr[2].columns > 0,
      false,
    ],
  };

  return marginInfo[wrapInfo.map((x) => x.length).join("")](arr);
}

