private _doRedraw() {
  if (this._disabled || this._paused) {
    return;
  }
  if (!this._fixedFramerate) {
    const now = Date.now();
    if (this._lastUpdateAt && now - this._lastUpdateAt < this._updateInterval) {
      return;
    }
    this._lastUpdateAt = now;
  }
  if (!this._showing && this._onScreen) {
    this._onScreen = false;
    let result = this._gauge.hide();
    if (this._hideCursor) {
      result += this._gauge.showCursor();
    }
    return this._writeTo.write(result);
  }
  if (!this._showing && !this._onScreen) {
    return;
  }
  if (this._showing && !this._onScreen) {
    this._onScreen = true;
    this._needsRedraw = true;
    if (this._hideCursor) {
      this._writeTo.write(this._gauge.hideCursor());
    }
  }
  if (!this._needsRedraw) {
    return;
  }
  if (!this._writeTo.write(this._gauge.show(this._status))) {
    this._paused = true;
    this._writeTo.on(
      "drain",
      callWith(this, function (this: any) {
        this._paused = false;
        this._doRedraw();
      })
    );
  }
}

private _formatPlainTextIndent(line: string) {
    const prev = this._lineAt(this._lineNum - 1);
    const prevIndent = this._prevIndent();
    const currIndent = this._currentIndent();

    if (
        currIndent > prevIndent &&
        !_isUndefinedOrWhitespace(prev) &&
        !this._builder.endsWith(MarkdownLineBreak) &&
        !this._builder.endsWith('\n\n') &&
        !_isHeader(prev)
    ) {
        this._builder = this._builder.slice(0, -1) + MarkdownLineBreak;
    }

    if (
        prevIndent > currIndent &&
        !_isUndefinedOrWhitespace(prev) &&
        !this._builder.endsWith(MarkdownLineBreak) &&
        !this._builder.endsWith('\n\n')
    ) {
        this._builder = this._builder.slice(0, -1) + MarkdownLineBreak;
    }

    if (prevIndent === 0 || this._builder.endsWith(MarkdownLineBreak) || this._builder.endsWith('\n\n')) {
        line = this._convertIndent(line);
    } else {
        line = line.trimStart();
    }
    return line;
}

export default function printConfirmationMessage(
  changeset: {
    releases: Array<Release>;
    summary: string;
  },
  repoHasMultiplePackages: boolean
) {
  function getReleasesOfType(type: VersionType) {
    return changeset.releases
      .filter((release) => release.type === type)
      .map((release) => release.name);
  }
  log("\n=== Summary of changesets ===");
  const majorReleases = getReleasesOfType("major");
  const minorReleases = getReleasesOfType("minor");
  const patchReleases = getReleasesOfType("patch");

  if (majorReleases.length > 0)
    log(`${pc.bold(pc.green("major"))}:  ${majorReleases.join(", ")}`);
  if (minorReleases.length > 0)
