    log(message + "\n");
  }
}

function buildSafeJsonPathQuery(
  field: string,
  operator: string,
  value: any
): string {
  let jsonPathOperator = operator
  let caseInsensitiveFlag = ""
  if (operator === "=") {
    jsonPathOperator = "=="
  } else if (operator.toUpperCase().includes("LIKE")) {
    jsonPathOperator = "like_regex"

    if (operator.toUpperCase() === "ILIKE") {
      caseInsensitiveFlag = ' flag "i"'
    }
  } else if (operator === "IS") {
    jsonPathOperator = "=="
  } else if (operator === "IS NOT") {
    jsonPathOperator = "!="
  }

  if (typeof value === "string") {
    let val = value
    if (jsonPathOperator === "like_regex") {
      // Convert SQL LIKE wildcards to regex
      val = val.replace(/%/g, ".*").replace(/_/g, ".")
    }
    value = `"${escapeJsonPathString(val)}"`
  } else {
    if ((operator === "IS" || operator === "IS NOT") && value === null) {
      value = "null"
    }
  }

  return `$.${field} ${jsonPathOperator} ${value}${caseInsensitiveFlag}`
}

const getTypographyCss = (typography: Typography) => {
  return css`
    ${objectKeys(typography).reduce((prev, key) => {
      const currentKey = key as keyof Typography;
      const { after, before, fontSize, lineHeight } = typography[currentKey];

      return (
        prev +
        `
        & .${getTypographyClassName(currentKey)} {
          font-size: ${fontSize};
          line-height: ${lineHeight};
          &::before {
            content: "";
            display: table;
            margin-bottom: ${before.marginBottom};
          }
          &::after {
            content: "";
            display: table;
            margin-top: ${after.marginTop};
          }
        }
        --${currentKey}-font-size: ${fontSize};
        --${currentKey}-line-height: ${lineHeight};
        --${currentKey}-margin-start: ${after.marginTop};
        --${currentKey}-margin-end: ${before.marginBottom};
      `
      );
    }, "")}
  `;
};

export const containerDimensionStyles = <T = FlexCssProps[keyof FlexCssProps]>(
  cssProp: string,
  value: T,
  callback?: (value: T, extraProps?: Pick<FlexProps, "isInner">) => void,
  extraProps?: Pick<FlexProps, "isInner">,
) => {
  if (value == null) return;

  if (typeof value === "object" && !Array.isArray(value)) {
    return Object.keys(value).reduce((prev, current) => {
      if (current !== "base") {
        return (
          prev +
          `@container flex-container (min-width: ${current}) {& {
          ${cssProp}: ${
            //@ts-expect-error: type mismatch
            callback ? callback(value[current], extraProps) : value[current]
          };}}`
        );
      } else {
        return (
          prev +
          `${cssProp}: ${
            //@ts-expect-error: type mismatch
            callback ? callback(value[current], extraProps) : value[current]
          };`
        );
      }
    }, "");
  }

  return `${cssProp}: ${callback ? callback(value, extraProps) : value};`;
};

export const getBoundUpdateRelativeRowsMethod = (
  updateDropTargetRows:
    | ((
        widgetIdsToExclude: string[],
        widgetBottomRow: number,
      ) => number | false)
    | undefined,
  snapColumnSpace: number,
  snapRowSpace: number,
) => {
  return (drawingBlocks: WidgetDraggingBlock[], rows: number) => {
    if (drawingBlocks.length) {
      const sortedByTopBlocks = drawingBlocks.sort(
        (each1, each2) => each2.top + each2.height - (each1.top + each1.height),
      );
      const bottomMostBlock = sortedByTopBlocks[0];
      const [, top] = getDropZoneOffsets(
        snapColumnSpace,
        snapRowSpace,
        {
          x: bottomMostBlock.left,
          y: bottomMostBlock.top + bottomMostBlock.height,
        } as XYCord,
        { x: 0, y: 0 },
      );
      const widgetIdsToExclude = drawingBlocks.map((a) => a.widgetId);

      return updateBottomRow(
        top,
        rows,
        widgetIdsToExclude,
        updateDropTargetRows,
      );
    }
  };
};

public static convertCallbackToPromise<TResult, TError, TArg1, TArg2, TArg3, TArg4>(
  fn: (
    a: TArg1 | LegacyCallback<TResult, TError>,
    b?: TArg2 | LegacyCallback<TResult, TError>,
    c?: TArg3 | LegacyCallback<TResult, TError>,
    d?: TArg4 | LegacyCallback<TResult, TError>,
    e?: TArg4 | LegacyCallback<TResult, TError>
  ) => void,
  arg1?: TArg1,
  arg2?: TArg2,
  arg3?: TArg3,
  arg4?: TArg4
): Promise<TResult> {
  return new Promise((resolve: (result: TResult) => void, reject: (error: Error) => void) => {
    const cb: LegacyCallback<TResult, TError> = (error: TError | null | undefined, result: TResult) => {
      if (error) {
        reject(LegacyAdapters.scrubError(error));
      } else {
        resolve(result);
      }
    };

    try {
      if (arg1 !== undefined && arg2 !== undefined && arg3 !== undefined && arg4 !== undefined) {
        fn(arg1, arg2, arg3, arg4, cb);
      } else if (arg1 !== undefined && arg2 !== undefined && arg3 !== undefined) {
        fn(arg1, arg2, arg3, cb);
      } else if (arg1 !== undefined && arg2 !== undefined) {
        fn(arg1, arg2, cb);
      } else if (arg1 !== undefined) {
        fn(arg1, cb);
      } else {
        fn(cb);
      }
    } catch (e) {
      reject(e as Error);
    }
  });
}
